const original = $items('Shop Daten eintragen')[0].json;
const html = String($json.body || $json.data || $json || '');
const emailRegex = /[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}/g;
const emails = [...new Set(html.match(emailRegex) || [])].filter(e => !e.match(/\.(png|jpg|jpeg|webp|gif)$/i));
const lower = html.toLowerCase();
const chatbotWords = ['chatbot', 'livechat', 'live chat', 'intercom', 'zendesk', 'tawk.to', 'tidio', 'crisp', 'gorgias'];
const chatbotFound = chatbotWords.some(word => lower.includes(word));
let score = 50;
if (emails.length > 0) score += 25;
if (!chatbotFound) score += 20;
if (original.niche) score += 5;
score = Math.min(score, 100);
const problem = chatbotFound
  ? 'Ich habe gesehen, dass Sie eventuell schon eine Chat-Loesung nutzen. Vielleicht kann man diese noch besser fuer Verkauf und Kundenservice einsetzen.'
  : 'Ich habe keinen klaren KI-Chatbot auf Ihrer Website gesehen. Dadurch bleiben viele Kundenfragen eventuell unbeantwortet.';
const message = `Betreff: Kurze Idee fuer ${original.shopName}\n\nHallo ${original.shopName}-Team,\n\nich habe mir Ihre Website angeschaut und hatte eine kurze Idee.\n\n${problem}\n\nIch baue einfache KI-Kundenservice-Bots fuer Online-Shops. Der Bot kann haeufige Fragen beantworten und Kunden schneller helfen.\n\nHaetten Sie Interesse an einer kostenlosen Mini-Analyse Ihrer Website?\n\nViele Gruesse\nKadir`;
return [{
  json: {
    shopName: original.shopName,
    shopUrl: original.shopUrl,
    niche: original.niche,
    emails: emails.join(', '),
    chatbotFound,
    score,
    note: chatbotFound ? 'Hat eventuell schon Chat oder Support-Tool.' : 'Guter Kandidat, kein klarer Chatbot gefunden.',
    message
  }
}];
